import sys

class TreeNode:
    def __init__(self, val: int):
        self.val = val
        self.left = None
        self.right = None

class Solution:
    def printPaths(self, root: TreeNode, path: list[int]) -> None:
        if root is None:
            return
        path.append(root.val)
        if root.left is None and root.right is None:
            print(' '.join(map(str, path)))
        else:
            self.printPaths(root.left, path)
            self.printPaths(root.right, path)
        path.pop()

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    n = int(next(it))
    vals = []
    for _ in range(n):
        try:
            vals.append(int(next(it)))
        except StopIteration:
            break
    # build tree in level order assuming complete binary tree layout
    nodes = [TreeNode(v) for v in vals]
    for i in range(n):
        left_idx = 2 * i + 1
        right_idx = 2 * i + 2
        if left_idx < n:
            nodes[i].left = nodes[left_idx]
        if right_idx < n:
            nodes[i].right = nodes[right_idx]
    root = nodes[0] if nodes else None
    sol = Solution()
    sol.printPaths(root, [])

