#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    void printPaths(TreeNode* root, vector<int>& path) {
        if (!root) return;
        path.push_back(root->val);
        if (!root->left && !root->right) {
            for (size_t i = 0; i < path.size(); ++i) {
                if (i) cout << ' ';
                cout << path[i];
            }
            cout << "\n";
        } else {
            printPaths(root->left, path);
            printPaths(root->right, path);
        }
        path.pop_back();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals(n);
    for (int i = 0; i < n; ++i) cin >> vals[i];
    vector<TreeNode*> nodes;
    nodes.reserve(n);
    for (int v : vals) nodes.push_back(new TreeNode(v));
    for (int i = 0; i < n; ++i) {
        int left = 2 * i + 1;
        int right = 2 * i + 2;
        if (left < n) nodes[i]->left = nodes[left];
        if (right < n) nodes[i]->right = nodes[right];
    }
    TreeNode* root = n ? nodes[0] : nullptr;
    Solution sol;
    vector<int> path;
    sol.printPaths(root, path);
    return 0;
}
